  ('fire-eq-eng-moex-00994', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '一定規模以上供公眾使用建築物施工時，對於消防安全設備機能有停止必要之規定，下列敘述何者為正確？', '["停止消防安全設備機能之工程，應儘量在營業時間以外進行，但飯店等全天營業之場所，應在日間進行", "火警自動警報設備停止使用時，應增設滅火器或室內消防栓之水帶等", "緊急廣播設備停止使用時，應移設至能裝設之場所", "自動撒水設備之機能停止時，應視工程狀況，採臨時裝設方式，使其發揮作用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
