  ('fire-eq-eng-moex-00997', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於共同防火管理，下列敘述何者有誤？', '["共同消防防護計畫由管理權人互推一人為召集人協議製定", "無法依規定互推召集人時，防火管理人得申請直轄市、縣（市）消防機關指定之", "集合住宅如屬11層以上之建築物應實施共同防火管理", "應設置共同防火管理協議會"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00998', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於火源責任者及防火負責人，下列敘述何者為正確？', '["設置火源責任者，係以樓層或區域為範圍", "茶水間等指定區域範圍內之用火用電安全管理工作，由防火負責人擔任，並定期檢查回報", "防火管理人得視場所規模、用途，依棟、樓或區，劃設責任區域，分別設置防火負責人及火源責任者", "火源責任者之任務為輔助防火管理人，並指導、監督防火負責人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00999', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防防護計畫實施滅火、通報及避難訓練，至少多久（a）應舉辦一次，每次不得少於多少（b）時間？', '["a：每半年  b：四小時", "a：每半年  b：六小時", "a：每年    b：四小時", "a：每年    b：八小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
