  ('fire-eq-eng-moex-01001', 'fire-eq-eng', 'fire-eq-eng-moex-099-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '關於乾粉滅火設備加、蓄壓用氣體量，下列何者為正確？', '["加壓用氣體使用氮氣時，在溫度攝氏三十五度，大氣壓力（表壓力）每平方公分零公斤狀態下，每一 公斤乾粉藥劑需氮氣二十公升以上", "加壓用氣體使用二氧化碳時，每一公斤乾粉藥劑需二氧化碳二十公克", "蓄壓用氣體使用氮氣時，在溫度攝氏三十五度，大氣壓力（表壓力）每平方公分零公斤狀態下，每一 公斤乾粉藥劑需氮氣二十公升以上，並加算清洗配管所需要量以上", "蓄壓用氣體使用二氧化碳時，每一公斤乾粉藥劑需二氧化碳二十公克並加算清洗配管所需要量以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "558d9c38d998", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
